Функция ${MethodName}Получить(Запрос)

	Ответ = Новый HTTPСервисОтвет(200);

	Попытка

		// Получение параметров
		{{#if HasParameter}}
		${ParameterName} = Запрос.ПараметрыURL.Получить("${ParameterUrlName}");
		Если ${ParameterName} = Неопределено Тогда
			Ответ.КодСостояния = 400;
			Ответ.УстановитьТелоИзСтроки("{\"error\": \"Missing parameter ${ParameterUrlName}\"}");
			Возврат Ответ;
		КонецЕсли;
		{{/if}}

		// Бизнес-логика
		${BusinessLogic}

		// Формирование ответа
		Результат = Новый Структура;
		${ResultCode}

		Ответ.Заголовки.Вставить("Content-Type", "application/json; charset=utf-8");
		Ответ.УстановитьТелоИзСтроки(JSON_ВСтроку(Результат));

	Исключение

		Ответ.КодСостояния = 500;
		Ответ.УстановитьТелоИзСтроки("{\"error\": \"" + ОписаниеОшибки() + "\"}")

	КонецПопытки;

	Возврат Ответ;

КонецФункции

Функция ${MethodName}Записать(Запрос)

	Ответ = Новый HTTPСервисОтвет(200);

	Попытка

		// Парсинг JSON из тела запроса
		ТелоЗапроса = Запрос.ПолучитьТелоКакСтроку();
		Данные = JSON_ИзСтроки(ТелоЗапроса);

		Если Данные = Неопределено Тогда
			Ответ.КодСостояния = 400;
			Ответ.УстановитьТелоИзСтроки("{\"error\": \"Invalid JSON\"}");
			Возврат Ответ;
		КонецЕсли;

		// Валидация данных
		{{#if ValidateRequired}}
		Если НЕ Данные.Свойство("${RequiredField}") Тогда
			Ответ.КодСостояния = 400;
			Ответ.УстановитьТелоИзСтроки("{\"error\": \"Missing field ${RequiredField}\"}");
			Возврат Ответ;
		КонецЕсли;
		{{/if}}

		// Бизнес-логика
		${BusinessLogic}

		// Формирование ответа
		Результат = Новый Структура;
		Результат.Вставить("success", Истина);
		${ResultCode}

		Ответ.КодСостояния = 201;
		Ответ.Заголовки.Вставить("Content-Type", "application/json; charset=utf-8");
		Ответ.УстановитьТелоИзСтроки(JSON_ВСтроку(Результат));

	Исключение

		Ответ.КодСостояния = 500;
		Ответ.УстановитьТелоИзСтроки("{\"error\": \"" + ОписаниеОшибки() + "\"}")

	КонецПопытки;

	Возврат Ответ;

КонецФункции

// ${Description}
//
// Параметры:
{{#each Parameters}}
//   ${name} - ${type} - ${description}
{{/each}}
//
// Возвращаемое значение:
//   ${ReturnType} - ${ReturnDescription}
//
Функция ${FunctionName}({{#each Parameters}}${name}{{#if hasDefault}} = ${default}{{/if}}{{#if !last}}, {{/if}}{{/each}}) Экспорт

	{{#if HasValidation}}
	// Валидация параметров
	${ValidationCode}
	{{/if}}

	${FunctionBody}

	Возврат ${ReturnValue};

КонецФункции

Функция ${OperationName}({{#each Parameters}}${name}{{#if !last}}, {{/if}}{{/each}})

	Попытка

		${BusinessLogic}

		// Формирование ответа
		Ответ = ФабрикаXDTO.Создать(ФабрикаXDTO.Тип("${Namespace}", "${ResponseType}"));
		${ResponseCode}

		Возврат Ответ;

	Исключение

		ВызватьИсключение ОписаниеОшибки();

	КонецПопытки;

КонецФункции

// Преобразование значения в JSON строку
Функция JSON_ВСтроку(Значение) Экспорт

	ЗаписьJSON = Новый ЗаписьJSON;
	ЗаписьJSON.УстановитьСтроку();

	НастройкиСериализации = Новый НастройкиСериализацииJSON;
	НастройкиСериализации.ФорматСериализацииДаты = ФорматДатыJSON.ISO;

	ЗаписатьJSON(ЗаписьJSON, Значение, НастройкиСериализации);

	Возврат ЗаписьJSON.Закрыть();

КонецФункции

// Чтение JSON строки в значение
Функция JSON_ИзСтроки(СтрокаJSON) Экспорт

	Если ПустаяСтрока(СтрокаJSON) Тогда
		Возврат Неопределено;
	КонецЕсли;

	Попытка

		ЧтениеJSON = Новый ЧтениеJSON;
		ЧтениеJSON.УстановитьСтроку(СтрокаJSON);

		Значение = ПрочитатьJSON(ЧтениеJSON, Истина);

		ЧтениеJSON.Закрыть();

		Возврат Значение;

	Исключение

		Возврат Неопределено;

	КонецПопытки;

КонецФункции

// Обработчик подписки "${SubscriptionName}"
// Источники: ${Sources}
// Событие: ${EventName}
//
Процедура ${HandlerName}(Источник, Отказ) Экспорт

	// Проверка типа источника
	{{#if CheckSourceType}}
	Если НЕ ТипЗнч(Источник) = Тип("${SourceType}") Тогда
		Возврат;
	КонецЕсли;
	{{/if}}

	{{#if CheckCondition}}
	// Проверка условия выполнения
	Если НЕ ${Condition} Тогда
		Возврат;
	КонецЕсли;
	{{/if}}

	// Логика обработчика
	${HandlerCode}

КонецПроцедуры

// Обработчик регламентного задания "${JobName}"
// Расписание: ${Schedule}
//
Процедура ${HandlerName}() Экспорт

	{{#if HasLock}}
	// Установка блокировки
	Блокировка = Новый БлокировкаДанных;
	ЭлементБлокировки = Блокировка.Добавить("${LockTable}");
	ЭлементБлокировки.Режим = РежимБлокировкиДанных.Исключительный;
	{{/if}}

	Попытка

		{{#if HasLock}}
		Блокировка.Заблокировать();
		{{/if}}

		// Основная логика
		${JobCode}

		{{#if HasLogging}}
		// Логирование
		ЗаписьЖурналаРегистрации(
			"${LogEventName}",
			УровеньЖурналаРегистрации.Информация,
			,
			,
			"${LogMessage}");
		{{/if}}

	Исключение

		ЗаписьЖурналаРегистрации(
			"${LogEventName}",
			УровеньЖурналаРегистрации.Ошибка,
			,
			,
			ОписаниеОшибки());

	КонецПопытки;

КонецПроцедуры
